1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEAR_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	
10	const COMPONENT_BASE_PREMIUM = 25;
11	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
12	const COMPONENT_BLOCK_SIZE = 3;
13	const COMPONENT_BLOCK_PREMIUM = 60;
14	
15	const NON_COMPONENT_BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	
22	const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);
23	
24	const basePremiumFor = (type: string): number =>
25	  isComponent(type) ? COMPONENT_BASE_PREMIUM : NON_COMPONENT_BASE_PREMIUM[type];
26	
27	type Item = { type: string; cursed?: boolean; enchantment?: number };
28	type QuoteStep = { op: "quote"; items: Item[] };
29	type Step = QuoteStep;
30	type Customer = { yearsWithMHPCO: number };
31	type Scenario = { customer: Customer; steps: Step[] };
32	
33	const groupedBasePremium = (type: string, count: number): number => {
34	  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
35	    return COMPONENT_BLOCK_PREMIUM;
36	  }
37	  return count * basePremiumFor(type);
38	};
39	
40	const countByType = (items: Item[]): Map<string, number> => {
41	  const counts = new Map<string, number>();
42	  for (const item of items) {
43	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
44	  }
45	  return counts;
46	};
47	
48	const sumBasePremiums = (items: Item[]): number =>
49	  Array.from(countByType(items)).reduce(
50	    (total, [type, count]) => total + groupedBasePremium(type, count),
51	    0,
52	  );
53	
54	const surchargeFor = (item: Item, applies: boolean, rate: number): number =>
55	  applies ? basePremiumFor(item.type) * rate : 0;
56	
57	const isCursed = (item: Item): boolean => item.cursed === true;
58	
59	const isHighlyEnchanted = (item: Item): boolean =>
60	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
61	
62	const itemSurchargeFor = (item: Item): number =>
63	  surchargeFor(item, isCursed(item), CURSE_SURCHARGE_RATE) +
64	  surchargeFor(item, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
65	
66	const sumItemSurcharges = (items: Item[]): number =>
67	  items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
68	
69	const firstInsuranceSurcharge = (basePremium: number): number =>
70	  basePremium * FIRST_INSURANCE_RATE;
71	
72	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
73	  customer.yearsWithMHPCO >= LOYALTY_YEAR_THRESHOLD
74	    ? basePremium * LOYALTY_DISCOUNT_RATE
75	    : 0;
76	
77	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
78	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
79	
80	const quotePremium = (
81	  items: Item[],
82	  customer: Customer,
83	  isFollowUp: boolean,
84	): number => {
85	  const basePremium = sumBasePremiums(items);
86	  const insurancePremium = Math.ceil(
87	    basePremium +
88	      sumItemSurcharges(items) +
89	      firstInsuranceSurcharge(basePremium) -
90	      loyaltyDiscount(basePremium, customer) -
91	      followUpDiscount(basePremium, isFollowUp),
92	  );
93	  return insurancePremium + PROCESSING_FEE;
94	};
95	
96	const runStep = (step: Step, customer: Customer, isFollowUp: boolean) => ({
97	  premium: quotePremium(step.items, customer, isFollowUp),
98	});
99	
100	export const runScenario = (scenario: Scenario): unknown => ({
101	  results: scenario.steps.map((step, index) =>
102	    runStep(step, scenario.customer, index > 0),
103	  ),
104	});
